from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent sentence describing the given triples."""
    if not triples:
        return ""

    # Assume all triples refer to the same subject (common in monument data)
    subject = triples[0].subject

    # Collect objects for each predicate (keep first occurrence for simplicity)
    info: dict[str, list[str]] = {}
    for t in triples:
        info.setdefault(t.predicate, []).append(t.object)

    parts: list[str] = []

    # Basic descriptive predicates
    if "category" in info:
        parts.append(f"is a {info['category'][0]}")
    if "dedicatedTo" in info:
        parts.append(f"dedicated to {info['dedicatedTo'][0]}")
    if "designer" in info:
        parts.append(f"designed by {info['designer'][0]}")
    if "material" in info:
        parts.append(f"made of {info['material'][0]}")

    # Location related predicates
    location_elems: list[str] = []
    for key in ("municipality", "location", "district", "state", "country"):
        if key in info:
            location_elems.append(info[key][0])
    if location_elems:
        parts.append("located in " + ", ".join(location_elems))

    # Date related predicates
    date_map = {
        "established": "established on",
        "foundingDate": "founded on",
        "inaugurationDate": "inaugurated on",
    }
    for pred, phr in date_map.items():
        if pred in info:
            parts.append(f"{phr} {info[pred][0]}")

    # Ownership predicates
    if "owner" in info:
        parts.append(f"owned by {info['owner'][0]}")
    elif "owningOrganisation" in info:
        parts.append(f"owned by {info['owningOrganisation'][0]}")

    # Combine parts into a single fluent sentence
    sentence = f"{subject} " + ", ".join(parts) + "."
    # Ensure the first character is capitalised
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

